219: GrpcStatusFormatter::Format GrpcStatusFormatter::parseFormat(absl::string_view format) {
220:   if (format.empty() || format == "CAMEL_STRING") {
221:     return GrpcStatusFormatter::CamelString;
222:   }
223: 
224:   if (format == "SNAKE_STRING") {
225:     return GrpcStatusFormatter::SnakeString;
226:   }
227:   if (format == "NUMBER") {
228:     return GrpcStatusFormatter::Number;
229:   }
230: 
231:   throwEnvoyExceptionOrPanic(
232:       "GrpcStatusFormatter only supports CAMEL_STRING, SNAKE_STRING or NUMBER.");
233: }
