57: absl::optional<std::string>
58: MetadataFormatter::formatMetadata(const envoy::config::core::v3::Metadata& metadata) const {
59:   ProtobufWkt::Value value = formatMetadataValue(metadata);
60:   if (value.kind_case() == ProtobufWkt::Value::kNullValue) {
61:     return absl::nullopt;
62:   }
63: 
64:   std::string str;
65:   if (value.kind_case() == ProtobufWkt::Value::kStringValue) {
66:     str = value.string_value();
67:   } else {
68: #ifdef ENVOY_ENABLE_YAML
69:     absl::StatusOr<std::string> json_or_error =
70:         MessageUtil::getJsonStringFromMessage(value, false, true);
71:     if (json_or_error.ok()) {
72:       str = json_or_error.value();
73:     } else {
74:       str = json_or_error.status().message();
75:     }
76: #else
77:     IS_ENVOY_BUG("Json support compiled out");
78: #endif
79:   }
80:   SubstitutionFormatUtils::truncate(str, max_length_);
81:   return str;
